SELECT COUNT(*) 
FROM material_outbound o


    o.handled_by LIKE CONCAT('%', #{keyword}, '%')



    AND o.status = #{status}



    AND DATE(o.outbound_date) >= #{startDate}



    AND DATE(o.outbound_date) <= #{endDate}

SELECT material_id, required_qty, stock_qty
FROM material_outbound_item
WHERE outbound_id = #{outboundId}

mapper.update:
UPDATE material_inventory
SET quantity = quantity - #{qty}
WHERE material_id = #{materialId}

UPDATE material_outbound_item
SET stock_qty = stock_qty - #{qty}
WHERE outbound_id = #{outboundId}
  AND material_id = #{materialId}

